import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class PathTraversalExample {

    private static final String BASE_DIRECTORY = "/var/data/";

    public static void main(String[] args) {
        String userInput = "../secret_files/important.txt";

        try {
            File requestedFile = new File(BASE_DIRECTORY, userInput).getCanonicalFile();

            if (!requestedFile.getPath().startsWith(BASE_DIRECTORY)) {
                System.err.println("Access to files outside the base directory is not allowed.");
                return;
            }

            FileInputStream fis = new FileInputStream(requestedFile);

            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }

            fis.close();
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

